@indicators({ rsi: rsi(series("close"), 14) })
function strategy() {
  if (rsi[-1] < 30) {
    return { action: "buy", confidence: (30 - rsi[-1]) / 30.0 };
  }
  if (in_position && rsi[-1] > 70) {
    return { action: "sell" };
  }
  return "none";
}

@indicators({ 
  sma_fast: sma(series("close"), 10), 
  sma_slow: sma(series("close"), 30) 
})
function strategy() {
  let prev_fast = sma_fast[-2];
  let prev_slow = sma_slow[-2];
  let curr_fast = sma_fast[-1];
  let curr_slow = sma_slow[-1];

  // Golden cross - bullish
  if (prev_fast <= prev_slow && curr_fast > curr_slow) {
    return { action: "buy" };
  }

  // Death cross - bearish
  if (prev_fast >= prev_slow && curr_fast < curr_slow) {
    return { action: "sell" };
  }

  return "none";
}

@indicators({ 
  bb: bollinger_bands(series("close"), 20, 2) 
})
function strategy() {
  let close_price = close[-1];
  let lower = bb.lower[-1];
  let upper = bb.upper[-1];

  // Buy when price touches lower band
  if (!in_position && close_price <= lower) {
    return { 
      action: "buy", 
      stop_loss: close_price * 0.98,
      take_profit: close_price * 1.04
    };
  }

  // Sell when price touches upper band
  if (in_position && close_price >= upper) {
    return { action: "sell" };
  }

  return "none";
}

@indicators({ 
  macd_data: macd(series("close"), 12, 26, 9) 
})
function strategy() {
  let macd_line = macd_data.macd[-1];
  let signal_line = macd_data.signal[-1];
  let prev_macd = macd_data.macd[-2];
  let prev_signal = macd_data.signal[-2];

  // Bullish crossover
  if (prev_macd <= prev_signal && macd_line > signal_line) {
    return { action: "buy" };
  }

  // Bearish crossover
  if (prev_macd >= prev_signal && macd_line < signal_line) {
    return { action: "sell" };
  }

  return "none";
}

@indicators({ 
  rsi: rsi(series("close"), 14),
  sma_fast: sma(series("close"), 20),
  sma_slow: sma(series("close"), 50)
})
function strategy() {
  let rsi_val = rsi[-1];
  let fast = sma_fast[-1];
  let slow = sma_slow[-1];
  let close_price = close[-1];

  // Buy when trend is up and RSI is oversold
  if (!in_position && fast > slow && rsi_val < 35) {
    return { 
      action: "buy",
      confidence: (35 - rsi_val) / 35.0,
      stop_loss: close_price * 0.97
    };
  }

  // Sell when RSI is overbought or trend reverses
  if (in_position && (rsi_val > 65 || fast < slow)) {
    return { action: "sell" };
  }

  return "none";
}
